ep2 = BRepBuilderAPI_MakePolygon()
for x, y, z in extrude_pts_2:
    ep2.Add(gp_Pnt(x - 1.0, y, z + Z_OFFSET))
ep2.Close()
ef2 = BRepBuilderAPI_MakeFace(ep2.Wire(), True)
if not ef2.IsDone():
    raise RuntimeError("Extrude profile 2 MakeFace failed.")
ep2_prism = BRepPrimAPI_MakePrism(ef2.Face(), gp_Vec(EXTRUDE_DIST_2, 0.0, 0.0))
if not ep2_prism.IsDone():
    raise RuntimeError("Extrude profile 2 MakePrism failed.")
extrude_solid_2 = ep2_prism.Shape()

print(f"Extrude profile 2: X=198 → X={198 + EXTRUDE_DIST_2} mm, Z offset={Z_OFFSET} mm")

# ═══════════════════════════════════════════════════════════════════════════════
# FUSE — join MainBody and ExtrudeProfile2 into one solid
# ═══════════════════════════════════════════════════════════════════════════════
from OCP.BRepAlgoAPI import BRepAlgoAPI_Fuse

fuse = BRepAlgoAPI_Fuse(result, extrude_solid_2)
fuse.Build()
if not fuse.IsDone():
    raise RuntimeError("Fuse failed.")
result = fuse.Shape()
print("MainBody and ExtrudeProfile2 fused into one solid.")

# ═══════════════════════════════════════════════════════════════════════════════
# COPY BOTH FEATURES + TRANSLATE +116.5mm in Y
# ═══════════════════════════════════════════════════════════════════════════════
Y_COPY = 116.5

trsf_copy = gp_Trsf()
trsf_copy.SetTranslation(gp_Vec(0.0, Y_COPY, 0.0))

# Copy extrude cut tool (extrude_solid) → cut into result
extrude_solid_copy = BRepBuilderAPI_Transform(extrude_solid, trsf_copy, True).Shape()
cut_copy = BRepAlgoAPI_Cut(result, extrude_solid_copy)
cut_copy.Build()
if not cut_copy.IsDone():
    raise RuntimeError("Extrude cut copy failed.")
result = cut_copy.Shape()
print(f"Extrude cut 1 copy applied at Y+{Y_COPY}mm.")

# Copy ExtrudeProfile2 (extrude_solid_2) → fuse into result
extrude_solid_2_copy = BRepBuilderAPI_Transform(extrude_solid_2, trsf_copy, True).Shape()
fuse_copy = BRepAlgoAPI_Fuse(result, extrude_solid_2_copy)
fuse_copy.Build()
if not fuse_copy.IsDone():
    raise RuntimeError("Fuse copy failed.")
result = fuse_copy.Shape()
print(f"ExtrudeProfile2 copy fused at Y+{Y_COPY}mm.")

