def arc_length_resample_3d(pts, n):
    """Resample a 3D polyline to exactly n points by arc-length interpolation."""
    segs = [math.sqrt((pts[i+1][0]-pts[i][0])**2 +
                      (pts[i+1][1]-pts[i][1])**2 +
                      (pts[i+1][2]-pts[i][2])**2)
            for i in range(len(pts)-1)]
    total = sum(segs)
    cumul = [0.0]
    for s in segs:
        cumul.append(cumul[-1] + s)
    targets = [total * i / (n - 1) for i in range(n)]
    result_pts = []
    for t in targets:
        for i in range(len(cumul)-1):
            if cumul[i] <= t <= cumul[i+1]:
                seg_len = cumul[i+1] - cumul[i]
                frac = (t - cumul[i]) / seg_len if seg_len > 1e-12 else 0.0
                x = pts[i][0] + frac * (pts[i+1][0] - pts[i][0])
                y = pts[i][1] + frac * (pts[i+1][1] - pts[i][1])
                z = pts[i][2] + frac * (pts[i+1][2] - pts[i][2])
                result_pts.append((x, y, z))
                break
    return result_pts

# Both profiles have 136 points — build wires directly, no resampling needed.
# Fix: P1 has two bad points at indices 97-98 causing a near-180° backtrack
# (Z goes 13.64→15.91→14.85→16.83 — both 97 and 98 are out of order).
# Remove both to restore a clean monotonic curve.
loft5_pts_1_fixed = loft5_pts_1[:97] + loft5_pts_1[99:]

# Fix start twist: both profiles start mid-curve at the inner tail of the '2'.
# P1's first structural corner (122° turn) is at norm≈0.393 of total arc.
# P2's first structural corner (122° turn) is at norm≈0.388 of total arc.
# The closure gaps differ (14.3mm vs 10.3mm), so after resampling index 0
# of each lands at slightly different positions on the shape → twist at seam.
# Fix: rotate P2 so its first 122°-corner is at index 0, then rotate P1 the same way,
# so both wires start at the same structural landmark.

def first_corner_index(pts, threshold=100.0):
    """Return index of first corner with turn angle > threshold."""
    n = len(pts)
    for i in range(1, n-1):
        ax=pts[i][0]-pts[i-1][0]; az=pts[i][2]-pts[i-1][2]
        bx=pts[i+1][0]-pts[i][0]; bz=pts[i+1][2]-pts[i][2]
        la=math.sqrt(ax**2+az**2); lb=math.sqrt(bx**2+bz**2)
        if la<1e-9 or lb<1e-9: continue
        cos_a=max(-1.,min(1.,(ax*bx+az*bz)/(la*lb)))
        if math.degrees(math.acos(cos_a)) > threshold:
            return i
    return 0

ci1 = first_corner_index(loft5_pts_1_fixed)  # ≈68
ci2 = first_corner_index(loft5_pts_2)         # ≈69

loft5_pts_1_aligned = loft5_pts_1_fixed[ci1:] + loft5_pts_1_fixed[:ci1]
loft5_pts_2_aligned = loft5_pts_2[ci2:] + loft5_pts_2[:ci2]

# Resample both to equal count
N5 = min(len(loft5_pts_1_aligned), len(loft5_pts_2_aligned))
loft5_r1 = arc_length_resample_3d(loft5_pts_1_aligned, N5)
loft5_r2 = arc_length_resample_3d(loft5_pts_2_aligned, N5)

