cut_loft6.Build()
if not cut_loft6.IsDone():
    raise RuntimeError("Loft body 6 cut failed.")
result = cut_loft6.Shape()
print("LoftBody6 cut applied to MainBody.")


# ═══════════════════════════════════════════════════════════════════════════════
# EXPORT — STEP + STL to Desktop
# ═══════════════════════════════════════════════════════════════════════════════
import os
from OCP.STEPControl import STEPControl_Writer, STEPControl_AsIs
from OCP.StlAPI import StlAPI_Writer
from OCP.IFSelect import IFSelect_RetDone

desktop = os.path.expanduser("~/Desktop")

# STEP export
step_path = os.path.join(desktop, "PP000002_MainBody.step")
step_writer = STEPControl_Writer()
step_writer.Transfer(result, STEPControl_AsIs)
status = step_writer.Write(step_path)
if status == IFSelect_RetDone:
    print(f"STEP exported → {step_path}")
else:
    print("STEP export failed.")

# STL export — mesh first, then write
from OCP.BRepMesh import BRepMesh_IncrementalMesh
from OCP.StlAPI import StlAPI

stl_path = os.path.join(desktop, "PP000002_MainBody.stl")
mesh = BRepMesh_IncrementalMesh(result, 0.1, False, 0.5)
mesh.Perform()
StlAPI.Write_s(result, stl_path, False)
print(f"STL exported  → {stl_path}")

# ═══════════════════════════════════════════════════════════════════════════════
# DISPLAY
# ═══════════════════════════════════════════════════════════════════════════════
show(result, reset_camera=Camera.ISO, names=["MainBody"])